/**
 * Error type exported via UniFFI. Maps 1:1 to internal `LayersError`.
 */
public enum UniFfiError {
    case NotInitialized
    case AlreadyInitialized
    case ShutDown
    case InvalidConfig(reason: String
    )
    case InvalidArgument(reason: String
    )
    case QueueFull(capacity: UInt32
    )
    case Serialization(reason: String
    )
    case Network(reason: String
    )
    case Http(status: UInt16, reason: String)
    case CircuitOpen
    case RateLimited(reason: String
    )
    case ConsentNotGranted(reason: String
    )
    case Persistence(reason: String
    )
    case RemoteConfig(reason: String
    )
    case EventDenied(reason: String
    )
    case Internal(reason: String
    )
}

#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
public struct FfiConverterTypeUniFFIError: FfiConverterRustBuffer {
    typealias SwiftType = UniFfiError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> UniFfiError {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        case 1: return .NotInitialized
        case 2: return .AlreadyInitialized
        case 3: return .ShutDown
        case 4: return try .InvalidConfig(
                reason: FfiConverterString.read(from: &buf)
            )
        case 5: return try .InvalidArgument(
                reason: FfiConverterString.read(from: &buf)
            )
        case 6: return try .QueueFull(
                capacity: FfiConverterUInt32.read(from: &buf)
            )
        case 7: return try .Serialization(
                reason: FfiConverterString.read(from: &buf)
            )
        case 8: return try .Network(
                reason: FfiConverterString.read(from: &buf)
            )
        case 9: return try .Http(
                status: FfiConverterUInt16.read(from: &buf),
                reason: FfiConverterString.read(from: &buf)
            )
        case 10: return .CircuitOpen
        case 11: return try .RateLimited(
                reason: FfiConverterString.read(from: &buf)
            )
        case 12: return try .ConsentNotGranted(
                reason: FfiConverterString.read(from: &buf)
            )
        case 13: return try .Persistence(
                reason: FfiConverterString.read(from: &buf)
            )
        case 14: return try .RemoteConfig(
                reason: FfiConverterString.read(from: &buf)
            )
        case 15: return try .EventDenied(
                reason: FfiConverterString.read(from: &buf)
            )
        case 16: return try .Internal(
                reason: FfiConverterString.read(from: &buf)
            )
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: UniFfiError, into buf: inout [UInt8]) {
        switch value {
        case .NotInitialized:
            writeInt(&buf, Int32(1))

        case .AlreadyInitialized:
            writeInt(&buf, Int32(2))

        case .ShutDown:
            writeInt(&buf, Int32(3))

        case let .InvalidConfig(reason):
            writeInt(&buf, Int32(4))
            FfiConverterString.write(reason, into: &buf)

        case let .InvalidArgument(reason):
            writeInt(&buf, Int32(5))
            FfiConverterString.write(reason, into: &buf)

        case let .QueueFull(capacity):
            writeInt(&buf, Int32(6))
            FfiConverterUInt32.write(capacity, into: &buf)

        case let .Serialization(reason):
            writeInt(&buf, Int32(7))
            FfiConverterString.write(reason, into: &buf)

        case let .Network(reason):
            writeInt(&buf, Int32(8))
            FfiConverterString.write(reason, into: &buf)

        case let .Http(status, reason):
            writeInt(&buf, Int32(9))
            FfiConverterUInt16.write(status, into: &buf)
            FfiConverterString.write(reason, into: &buf)

        case .CircuitOpen:
            writeInt(&buf, Int32(10))

        case let .RateLimited(reason):
            writeInt(&buf, Int32(11))
            FfiConverterString.write(reason, into: &buf)

        case let .ConsentNotGranted(reason):
